  def test_stream_webhook_canonical_alias_resolves
    # Spec §7: Stream::Webhook is the canonical name; should alias StreamChat::Webhook.
    assert_equal StreamChat::Webhook, Stream::Webhook
  end

  def test_parse_event_returns_unknown_event_for_unknown_discriminator
    body = '{"type":"totally.made.up","created_at":"2026-05-08T00:00:00Z"}'
    event = StreamChat::Webhook.parse_event(body)
    assert_kind_of StreamChat::Webhook::UnknownEvent, event
    assert_equal 'totally.made.up', event.type
    refute_nil event.created_at
    assert_equal 'totally.made.up', event.raw['type']
  end

