# ---------------------------------------------------------------------------
# Fixture-driven conformance tests. Fixtures live at test/fixtures/webhooks/
# (one subdirectory per case for happy path; _invalid/ for negative cases).
# ---------------------------------------------------------------------------
class WebhookConformanceTest < Minitest::Test
  CANONICAL_TEST_SECRET = 'test_secret_do_not_use_in_production'
  FIXTURE_ROOT = File.expand_path('fixtures/webhooks', __dir__).freeze

  def fixtures_present?
    File.directory?(FIXTURE_ROOT)
  end

  def each_happy_dir
    return unless fixtures_present?

    Dir.children(FIXTURE_ROOT).sort.each do |name|
      next if name == '_invalid'

      dir = File.join(FIXTURE_ROOT, name)
      next unless File.directory?(dir)

      yield name, dir
    end
  end

  def test_happy_fixtures
    skip 'webhook conformance fixtures not present' unless fixtures_present?

    each_happy_dir do |name, dir|
      body = File.binread(File.join(dir, 'body.json'))
      body_gz = File.binread(File.join(dir, 'body.gz'))
      sqs_compressed = File.read(File.join(dir, 'sqs_body.txt')).strip
      sqs_raw = File.read(File.join(dir, 'sqs_body_uncompressed.txt')).strip
      sns = File.read(File.join(dir, 'sns_notification.txt')).strip
      sig = File.read(File.join(dir, 'signature.txt')).strip

      assert StreamChat::Webhook.verify_signature(body, sig, CANONICAL_TEST_SECRET),
             "verify_signature failed for #{name}"
      refute_nil StreamChat::Webhook.parse_event(body),
                 "parse_event nil for #{name}"
      refute_nil StreamChat::Webhook.verify_and_parse_webhook(body, sig, CANONICAL_TEST_SECRET),
                 "verify_and_parse_webhook (identity) failed for #{name}"
      refute_nil StreamChat::Webhook.verify_and_parse_webhook(body_gz, sig, CANONICAL_TEST_SECRET),
                 "verify_and_parse_webhook (gzip) failed for #{name}"
      refute_nil StreamChat::Webhook.parse_sqs(sqs_compressed),
                 "parse_sqs (compressed) failed for #{name}"
      refute_nil StreamChat::Webhook.parse_sqs(sqs_raw),
                 "parse_sqs (uncompressed) failed for #{name}"
      refute_nil StreamChat::Webhook.parse_sns(sns),
                 "parse_sns failed for #{name}"
    end
  end

  def neg_dir(name)
    File.join(FIXTURE_ROOT, '_invalid', name)
  end

  def test_tampered_body
    skip 'fixtures not present' unless fixtures_present?

    body = File.binread(File.join(neg_dir('tampered_body'), 'body.json'))
    sig = File.read(File.join(neg_dir('tampered_body'), 'signature.txt')).strip
    err = assert_raises(StreamChat::Webhook::InvalidWebhookError) do
      StreamChat::Webhook.verify_and_parse_webhook(body, sig, CANONICAL_TEST_SECRET)
    end
    assert_includes err.message, 'signature mismatch'
  end

  def test_unknown_type_returns_unknown_event
    skip 'fixtures not present' unless fixtures_present?

    body = File.binread(File.join(neg_dir('unknown_type'), 'body.json'))
    result = StreamChat::Webhook.parse_event(body)
    assert_kind_of StreamChat::Webhook::UnknownEvent, result
    assert_equal 'totally.made.up', result.type
  end

  def test_missing_type
    skip 'fixtures not present' unless fixtures_present?

    body = File.binread(File.join(neg_dir('missing_type'), 'body.json'))
    err = assert_raises(StreamChat::Webhook::InvalidWebhookError) do
      StreamChat::Webhook.parse_event(body)
    end
    assert_includes err.message, "missing 'type'"
  end

  def test_malformed_json
    skip 'fixtures not present' unless fixtures_present?

    body = File.binread(File.join(neg_dir('malformed_json'), 'body.json'))
    err = assert_raises(StreamChat::Webhook::InvalidWebhookError) do
      StreamChat::Webhook.parse_event(body)
    end
    assert_includes err.message, 'failed to parse webhook payload'
  end

  def test_empty_body
    skip 'fixtures not present' unless fixtures_present?

    body = File.binread(File.join(neg_dir('empty_body'), 'body.json'))
    err = assert_raises(StreamChat::Webhook::InvalidWebhookError) do
      StreamChat::Webhook.parse_event(body)
    end
    assert_includes err.message, 'must not be empty'
  end

  def test_bad_compression
    skip 'fixtures not present' unless fixtures_present?

    body = File.binread(File.join(neg_dir('bad_compression'), 'body.gz'))
    err = assert_raises(StreamChat::Webhook::InvalidWebhookError) do
      StreamChat::Webhook.gunzip_payload(body)
    end
    assert_includes err.message, 'gzip decompression failed'
  end

  def test_bad_base64
    skip 'fixtures not present' unless fixtures_present?

    msg = File.read(File.join(neg_dir('bad_base64'), 'sqs_body.txt')).strip
    err = assert_raises(StreamChat::Webhook::InvalidWebhookError) do
      StreamChat::Webhook.parse_sqs(msg)
    end
    assert_includes err.message, 'base64'
  end

  def test_bad_sns_envelope
    skip 'fixtures not present' unless fixtures_present?

    notif = File.read(File.join(neg_dir('bad_sns_envelope'), 'sns_notification.txt')).strip
    err = assert_raises(StreamChat::Webhook::InvalidWebhookError) do
      StreamChat::Webhook.parse_sns(notif)
    end
    assert_includes err.message, 'SNS envelope'
  end
end
